const drafts = $input.first().json;
const rows = Array.isArray(drafts) ? drafts : [];

const stats = {
  total: rows.length,
  published: rows.filter(r => r.status === 'published').length,
  approved: rows.filter(r => r.status === 'approved').length,
  rejected: rows.filter(r => r.status === 'rejected').length,
  pending: rows.filter(r => r.status === 'pending_approval').length,
  postTypes: {}
};

rows.forEach(r => {
  stats.postTypes[r.post_type] = (stats.postTypes[r.post_type] || 0) + 1;
});

return [{ json: { stats, weekStart: $('Calculate Date Range').first().json.since } }];

const response = $input.first().json;
const report = response.content?.[0]?.text || 'Failed to generate report';
const stats = $('Aggregate Stats').first().json.stats;

const message = `📊 <b>GHL Marketing — Weekly Report</b>\n` +
  `Week ending ${new Date().toLocaleDateString('en-AU', {weekday:'long',day:'numeric',month:'long',year:'numeric'})}\n\n` +
  `<b>Stats:</b>\n` +
  `• Total drafts: ${stats.total}\n` +
  `• Published: ${stats.published}\n` +
  `• Approved: ${stats.approved}\n` +
  `• Rejected: ${stats.rejected}\n` +
  `• Pending: ${stats.pending}\n\n` +
  `<b>AI Summary:</b>\n${report}`;

return [{ json: { message } }];

